# exceptions.py — Custom exception hierarchy for a data pipeline

class PipelineError(Exception):
    """Base class for all pipeline errors."""
    pass

# --- Transient: safe to retry ---
class TransientError(PipelineError):
    """Temporary failure; retry is appropriate."""
    pass

class NetworkTimeoutError(TransientError):
    pass

class RateLimitError(TransientError):
    def __init__(self, message, retry_after: float = 60.0):
        super().__init__(message)
        self.retry_after = retry_after

class TemporaryServiceError(TransientError):
    pass

# --- Permanent: do NOT retry; route to DLQ ---
class PermanentError(PipelineError):
    """Retrying will not help; requires human intervention or discard."""
    pass

class SchemaValidationError(PermanentError):
    def __init__(self, message, record=None, field=None):
        super().__init__(message)
        self.record = record
        self.field = field

class DataIntegrityError(PermanentError):
    pass

class BusinessRuleViolation(PermanentError):
    pass

# --- Systemic: abort the pipeline stage ---
class SystemicError(PipelineError):
    """The entire system or dependency is broken."""
    pass

class DatabaseConnectionError(SystemicError):
    pass

class ConfigurationError(SystemicError):
    pass

import logging
from tenacity import (
    retry,
    stop_after_attempt,
    wait_exponential,
    wait_random_exponential,
    retry_if_exception_type,
    before_sleep_log,
    RetryError,
)
from exceptions import TransientError, RateLimitError

logger = logging.getLogger(__name__)

@retry(
    retry=retry_if_exception_type(TransientError),
    wait=wait_random_exponential(multiplier=1, min=2, max=60),  # jitter prevents thundering herd
    stop=stop_after_attempt(5),
    before_sleep=before_sleep_log(logger, logging.WARNING),
    reraise=True,  # re-raise the original exception after exhausting retries
)
def fetch_from_api(url: str, params: dict) -> dict:
    """Fetch data from an external API with automatic retry on transient errors."""
    import httpx
    try:
        response = httpx.get(url, params=params, timeout=10.0)
        if response.status_code == 429:
            retry_after = float(response.headers.get("Retry-After", 60))
            raise RateLimitError(
                f"Rate limited by {url}",
                retry_after=retry_after,
            )
        if response.status_code >= 500:
            raise TransientError(f"Server error {response.status_code} from {url}")
        response.raise_for_status()
        return response.json()
    except httpx.TimeoutException as e:
        raise NetworkTimeoutError(f"Timeout calling {url}") from e

import time
import random

def retry_with_backoff(func, args=(), kwargs=None, max_attempts=5, base_delay=2.0):
    """
    Retry a function with exponential backoff and jitter.
    Returns the result on success, raises the last exception on exhaustion.
    """
    if kwargs is None:
        kwargs = {}
    last_exception = None

    for attempt in range(1, max_attempts + 1):
        try:
            return func(*args, **kwargs)
        except TransientError as e:
            last_exception = e
            if attempt == max_attempts:
                break
            # Exponential backoff: 2^attempt seconds + random jitter [0, 1)
            delay = (base_delay ** attempt) + random.random()
            delay = min(delay, 60.0)  # cap at 60 seconds
            logger.warning(
                "Transient error on attempt %d/%d. Retrying in %.1fs. Error: %s",
                attempt, max_attempts, delay, e,
            )
            time.sleep(delay)

    raise last_exception

import logging
import json
import sys
from datetime import datetime, timezone


class JSONFormatter(logging.Formatter):
    """Emits each log record as a single JSON object — machine-parseable."""

    def format(self, record: logging.LogRecord) -> str:
        log_entry = {
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "level": record.levelname,
            "logger": record.name,
            "message": record.getMessage(),
            "module": record.module,
            "line": record.lineno,
        }
        # Attach extra fields passed via `extra=` parameter
        for key, value in record.__dict__.items():
            if key.startswith("pipeline_"):
                log_entry[key] = value

        if record.exc_info:
            log_entry["exception"] = self.formatException(record.exc_info)

        return json.dumps(log_entry)


def configure_pipeline_logging(level: str = "INFO") -> None:
    handler = logging.StreamHandler(sys.stdout)
    handler.setFormatter(JSONFormatter())
    root = logging.getLogger()
    root.setLevel(getattr(logging, level.upper()))
    root.handlers = [handler]

import json
from pathlib import Path

class CheckpointManager:
    """Tracks pipeline progress — allows resuming from last successful position."""

    def __init__(self, path: Path):
        self.path = path

    def load(self) -> dict:
        if self.path.exists():
            return json.loads(self.path.read_text())
        return {}

    def save(self, state: dict) -> None:
        # Atomic write: write to temp file, then rename (rename is atomic on POSIX)
        tmp = self.path.with_suffix(".tmp")
        tmp.write_text(json.dumps(state, indent=2))
        tmp.rename(self.path)
        logger.debug("Checkpoint saved: %s", state)


# Usage pattern
checkpoint = CheckpointManager(Path("checkpoints/pipeline.json"))
state = checkpoint.load()
last_offset = state.get("last_offset", 0)

for batch in read_source(from_offset=last_offset, batch_size=1000):
    successful, _ = process_batch(batch.records, dlq)
    upsert_records(db_conn, successful, run_id=RUN_ID)
    # Only advance checkpoint after successful write
    last_offset = batch.end_offset
    checkpoint.save({"last_offset": last_offset, "run_id": RUN_ID})
